WITH active_cameras AS (
    SELECT camera_id FROM cameras WHERE status = 'active'
),
images_taken_by_active_cameras AS (
    SELECT image_id FROM images WHERE camera_id IN (SELECT camera_id FROM active_cameras)
)
SELECT *
FROM detections d
WHERE d.image_id IN (SELECT image_id FROM images_taken_by_active_cameras)
ORDER BY d.confidence DESC;

SELECT resolution 
FROM cameras 
WHERE camera_id = 0;

SELECT COUNT(*) AS image_count
FROM images
WHERE camera_id = (SELECT camera_id FROM cameras WHERE camera_name = 'CCTV Camera 1');

SELECT COUNT(*) 
FROM images
WHERE camera_id IN (SELECT camera_id FROM cameras WHERE resolution = '4K');

SELECT COUNT(*) 
FROM images 
WHERE camera_id = (SELECT camera_id FROM cameras WHERE camera_name = 'Drone Camera 2');
